/**
 * Curriculum Loader
 *
 * Loads curriculum data for different learner modes.
 * Supports multiple curriculum JSON files generated by convert-curriculum.js
 */

// Import curriculum files (Vite handles JSON imports automatically).
// These are authored chapter sources; the runtime roadmap reads from
// src/data/unified_db.json (Units 10-18 are appended there).
import exploreVietnamA1 from './explore_vietnam.json';
import exploreVietnamA2B1 from './explore_vietnam_a2_b1.json';

function mergeChapters(...chapters) {
    const base = chapters[0];
    const units = chapters.flatMap(c => c.units || []);
    const lessons = chapters.flatMap(c => c.lessons || []);
    const grammarTags = chapters.flatMap(c => c.grammarTags || []);
    return {
        ...base,
        units,
        lessons,
        grammarTags,
        meta: {
            ...base.meta,
            stats: {
                units: units.length,
                lessons: lessons.length,
                vocabulary: lessons.reduce((s, l) => s + (l.words?.length || 0), 0),
                sentences: lessons.reduce((s, l) => s + (l.sentences?.length || 0), 0),
                conversations: lessons.reduce((s, l) => s + (l.conversations?.length || 0), 0),
                grammarTags: grammarTags.length,
            },
        },
    };
}

const exploreVietnam = mergeChapters(exploreVietnamA1, exploreVietnamA2B1);

// Registry of all curricula by mode ID
const CURRICULA = {
    explore_vietnam: exploreVietnam,
};

/**
 * Get curriculum for a specific learner mode
 * @param {string} modeId - Learner mode ID (e.g., 'explore_vietnam')
 * @returns {Object} Curriculum data or default
 */
export function getCurriculum(modeId) {
    return CURRICULA[modeId] || CURRICULA.explore_vietnam;
}

/**
 * Get all lessons for a mode, optionally filtered by unit
 * @param {string} modeId
 * @param {string} [unitId] - Optional unit filter
 * @returns {Array} Lesson definitions
 */
export function getLessonsForMode(modeId, unitId = null) {
    const curriculum = getCurriculum(modeId);
    if (!unitId) return curriculum.lessons;
    return curriculum.lessons.filter(l => l.unit === unitId);
}

/**
 * Get all units for a mode
 * @param {string} modeId
 * @returns {Array} Unit definitions
 */
export function getUnitsForMode(modeId) {
    const curriculum = getCurriculum(modeId);
    return curriculum.units || [];
}

/**
 * Get a specific lesson by ID
 * @param {string} modeId
 * @param {string} lessonId
 * @returns {Object|null} Lesson definition
 */
export function getLessonById(modeId, lessonId) {
    const curriculum = getCurriculum(modeId);
    return curriculum.lessons.find(l => l.id === lessonId) || null;
}

/**
 * Get grammar tag definitions
 * @param {string} modeId
 * @returns {Array} Grammar tag definitions
 */
export function getGrammarTags(modeId) {
    const curriculum = getCurriculum(modeId);
    return curriculum.grammarTags || [];
}

/**
 * Convert curriculum lesson to db.js LESSON_DEFS format
 * (for compatibility with existing exercise generator)
 * @param {Object} lesson - Curriculum lesson
 * @returns {Object} LESSON_DEFS-compatible format
 */
export function toLessonDef(lesson) {
    return {
        id: lesson.id,
        unit: lesson.unit,
        title: lesson.title,
        nodeId: lesson.nodeId,
        quizId: lesson.quizId,
        quizLabel: lesson.quizLabel,
        nodeIndex: lesson.nodeIndex,
        difficulty: lesson.difficulty,
        cefr: lesson.cefr,
        xp: lesson.xp,
        topic: lesson.topic,
        focus: lesson.focus,
        words: lesson.words.map(w => ({
            id: w.id,
            vi: w.vi,
            en: w.en,
            emoji: w.emoji,
            dialect: w.dialect,
        })),
        sentences: lesson.sentences.map(s => ({
            id: s.id,
            vi: s.vi,
            en: s.en,
        })),
    };
}

/**
 * Get all LESSON_DEFS for a mode (for bulk loading into db.js)
 * @param {string} modeId
 * @returns {Array} LESSON_DEFS-compatible array
 */
export function getAllLessonDefs(modeId) {
    const lessons = getLessonsForMode(modeId);
    return lessons.map(toLessonDef);
}

/**
 * Stats about loaded curriculum
 * @param {string} modeId
 * @returns {Object} Statistics
 */
export function getCurriculumStats(modeId) {
    const curriculum = getCurriculum(modeId);
    return curriculum.meta?.stats || {
        units: curriculum.units?.length || 0,
        lessons: curriculum.lessons?.length || 0,
        vocabulary: curriculum.lessons?.reduce((sum, l) => sum + l.words.length, 0) || 0,
        sentences: curriculum.lessons?.reduce((sum, l) => sum + l.sentences.length, 0) || 0,
    };
}

// Export curriculum data directly for convenience
export { exploreVietnam };

// Default export
export default {
    getCurriculum,
    getLessonsForMode,
    getUnitsForMode,
    getLessonById,
    getGrammarTags,
    toLessonDef,
    getAllLessonDefs,
    getCurriculumStats,
};
